/**
 * frontend/src/components/UseCaseLibrary.jsx
 *
 * Screen 1 — Use Case Library.
 *
 * Fetches GET /api/use-cases on load, renders 16 cards in a 2-column grid
 * under four family sections. Card click → GET /api/use-cases/{id} →
 * onSelect({ card, familyKey }) for navigation to IntakeFlow with first_question.
 *
 * Figma frame: 01-UseCase-Library
 */

import React, { useCallback, useEffect, useMemo, useState } from "react";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:8000";

const DS = {
  bg: "#0d0d0d",
  surface: "#1e1e1e",
  border: "#2a2a2a",
  borderFocus: "#E8712A",
  textPrimary: "#e8e8e8",
  textSecondary: "#888888",
};

const FAMILY_ORDER = [
  "learning_career",
  "research_decision",
  "strategy_planning",
  "technical_build",
];

const FAMILY_TITLES = {
  learning_career: "Learning & Career",
  research_decision: "Research & Decision",
  strategy_planning: "Strategy & Planning",
  technical_build: "Technical Build",
};

function formatTier(typicalTier) {
  if (typicalTier === "deep_thinking") return "Deep Thinking";
  if (typicalTier === "quick") return "Quick";
  if (typicalTier === "smart") return "Smart";
  return typicalTier?.replace(/_/g, " ") || "—";
}

/**
 * @param {Object} props
 * @param {function} props.onSelect - called with `{ card, familyKey }` after GET /api/use-cases/{id} succeeds; `card` includes `first_question`
 */
function UseCaseLibrary({ onSelect }) {
  const [library, setLibrary] = useState(null);
  const [loadError, setLoadError] = useState(null);
  const [fetchingId, setFetchingId] = useState(null);
  const [clickError, setClickError] = useState(null);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/api/use-cases`);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        if (!cancelled) {
          setLibrary(data);
          setLoadError(null);
        }
      } catch (e) {
        if (!cancelled) {
          setLoadError(e.message || "Failed to load use cases");
          setLibrary(null);
        }
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const sections = useMemo(() => {
    if (!library) return [];
    return FAMILY_ORDER.map((key) => ({
      key,
      title: FAMILY_TITLES[key] || key,
      cards: Array.isArray(library[key]) ? library[key] : [],
    })).filter((s) => s.cards.length > 0);
  }, [library]);

  const handleCardClick = useCallback(
    async (cardId, familyKey) => {
      setClickError(null);
      setFetchingId(cardId);
      try {
        const res = await fetch(`${API_BASE}/api/use-cases/${encodeURIComponent(cardId)}`);
        if (!res.ok) {
          if (res.status === 404) throw new Error("Use case not found");
          throw new Error(`HTTP ${res.status}`);
        }
        const card = await res.json();
        if (typeof onSelect === "function") {
          onSelect({ card, familyKey });
        }
      } catch (e) {
        setClickError(e.message || "Could not open this use case");
      } finally {
        setFetchingId(null);
      }
    },
    [onSelect]
  );

  const shellStyle = {
    minHeight: "100vh",
    backgroundColor: DS.bg,
    color: DS.textPrimary,
    padding: "2rem clamp(1rem, 4vw, 3rem)",
    fontFamily:
      'ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif',
  };

  const headerStyle = {
    maxWidth: "72rem",
    margin: "0 auto 2.5rem",
  };

  const taglineStyle = {
    margin: "0.35rem 0 0",
    fontSize: "0.95rem",
    color: DS.textSecondary,
    fontWeight: 400,
  };

  const sectionTitleStyle = (isFirst) => ({
    fontSize: "1.1rem",
    fontWeight: 600,
    letterSpacing: "0.02em",
    color: DS.textPrimary,
    margin: isFirst ? "1rem 0 1rem" : "2.5rem 0 1rem",
    paddingBottom: "0.5rem",
    borderBottom: `1px solid ${DS.border}`,
  });

  return (
    <div style={shellStyle}>
      <style>{`
        .art-use-case-grid {
          display: grid;
          grid-template-columns: repeat(2, minmax(0, 1fr));
          gap: 1rem;
        }
        @media (max-width: 719px) {
          .art-use-case-grid { grid-template-columns: 1fr; }
        }
      `}</style>
      <header style={headerStyle}>
        <h1 style={{ margin: 0, fontSize: "1.75rem", fontWeight: 700 }}>ai-roundtable</h1>
        <p style={taglineStyle}>Putting the best frontier minds to work.</p>
      </header>

      {loadError && (
        <p
          style={{
            maxWidth: "72rem",
            margin: "0 auto 1rem",
            color: "#f87171",
            fontSize: "0.9rem",
          }}
          role="alert"
        >
          {loadError}
        </p>
      )}

      {clickError && (
        <p
          style={{
            maxWidth: "72rem",
            margin: "0 auto 1rem",
            color: "#f87171",
            fontSize: "0.9rem",
          }}
          role="alert"
        >
          {clickError}
        </p>
      )}

      {!library && !loadError && (
        <p style={{ color: DS.textSecondary, maxWidth: "72rem", margin: "0 auto" }}>
          Loading use cases…
        </p>
      )}

      {sections.map(({ key, title, cards }, idx) => (
        <section key={key} style={{ maxWidth: "72rem", margin: "0 auto" }}>
          <h2 style={sectionTitleStyle(idx === 0)}>{title}</h2>
          <div className="art-use-case-grid">
            {cards.map((card) => (
              <button
                key={card.id}
                type="button"
                disabled={fetchingId !== null}
                onClick={() => handleCardClick(card.id, key)}
                style={{
                  textAlign: "left",
                  cursor: fetchingId !== null ? "wait" : "pointer",
                  backgroundColor: DS.surface,
                  color: DS.textPrimary,
                  border: `1px solid ${DS.border}`,
                  borderRadius: "8px",
                  padding: "1.15rem 1.25rem",
                  display: "flex",
                  flexDirection: "column",
                  gap: "0.65rem",
                  transition: "border-color 0.15s ease, box-shadow 0.15s ease",
                  opacity: fetchingId === card.id ? 0.85 : 1,
                }}
                onMouseEnter={(e) => {
                  if (fetchingId !== null) return;
                  e.currentTarget.style.borderColor = DS.borderFocus;
                  e.currentTarget.style.boxShadow = `0 0 0 1px ${DS.borderFocus}`;
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.borderColor = DS.border;
                  e.currentTarget.style.boxShadow = "none";
                }}
                onFocus={(e) => {
                  e.currentTarget.style.borderColor = DS.borderFocus;
                  e.currentTarget.style.outline = "none";
                  e.currentTarget.style.boxShadow = `0 0 0 1px ${DS.borderFocus}`;
                }}
                onBlur={(e) => {
                  e.currentTarget.style.borderColor = DS.border;
                  e.currentTarget.style.boxShadow = "none";
                }}
              >
                <span style={{ fontSize: "1.05rem", fontWeight: 600, lineHeight: 1.35 }}>
                  {card.title}
                </span>
                <span style={{ fontSize: "0.875rem", color: DS.textSecondary, lineHeight: 1.5 }}>
                  {card.description}
                </span>
                <span style={{ fontSize: "0.8rem", color: DS.textSecondary }}>
                  <span style={{ color: DS.textPrimary }}>Output:</span> {card.output}
                </span>
                <span
                  style={{
                    marginTop: "0.15rem",
                    fontSize: "0.75rem",
                    fontWeight: 600,
                    textTransform: "uppercase",
                    letterSpacing: "0.06em",
                    color: DS.borderFocus,
                  }}
                >
                  {formatTier(card.typical_tier)}
                </span>
                {fetchingId === card.id && (
                  <span style={{ fontSize: "0.75rem", color: DS.textSecondary }}>Opening…</span>
                )}
              </button>
            ))}
          </div>
        </section>
      ))}
    </div>
  );
}

export default UseCaseLibrary;
